mapper.insert:
INSERT INTO USERS (
    AUTH_ID, EMPLOYEE_ID, PASSWORD, DEPARTMENT, NAME,
    BIRTH, PHONE, EMAIL, ADDRESS, HIRE_DATE, REMARK
) VALUES (
    #{authId}, #{employeeId}, #{password}, #{department}, #{name},
    #{birth}, #{phone}, #{email}, #{address}, #{hireDate}, #{remark}
)

mapper.select:
SELECT U.USER_ID AS userId, U.AUTH_ID AS authId, U.EMPLOYEE_ID AS employeeId, U.DEPARTMENT AS department, U.NAME AS name, U.BIRTH AS birth, U.PHONE AS phone, U.EMAIL AS email, U.ADDRESS AS address, U.HIRE_DATE AS hireDate, U.RETIRE_DATE AS retireDate, U.STATUS AS status, U.USE_YN AS useYn, U.REMARK AS remark, U.CREATED_AT AS createdAt, U.UPDATED_AT AS updatedAt, A.AUTH_CODE AS authCode, A.AUTH_NAME AS authName FROM USERS U JOIN AUTHORITY_CODE A ON U.AUTH_ID = A.AUTH_ID WHERE 1=1
AND U.NAME LIKE CONCAT('%', #{name}, '%')
AND U.AUTH_ID = #{authId}
AND U.STATUS = #{status}
AND U.USE_YN = #{useYn}
ORDER BY U.USER_ID DESC

mapper.update:
UPDATE USERS
SET
    PASSWORD = #{password}
WHERE USER_ID = #{userId}
